import React from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import { GoogleOAuthProvider } from '@react-oauth/google';

// Importação das páginas que estão dentro da pasta 'src/pages'
import Home from './pages/Home';
import Apresentacao from './pages/Apresentacao';
import Cadastro from './pages/Cadastro';
function App() {
  // Este é o Client ID que geraste no Google Cloud Console
  const clientId = "688882610281-60007selpnj3ulv66gfg6manilek822t.apps.googleusercontent.com";

  return (
    <GoogleOAuthProvider clientId={clientId}>
      <Router>
        <div className="App">
          {/* O componente Routes define qual tela será exibida com base na URL */}
          <Routes>
            {/* Tela Inicial - Requisito 1 */}
            <Route path="/" element={<Home />} />

            {/* Tela de Apresentação da Dupla - Requisito 2 */}
            <Route path="/dupla" element={<Apresentacao />} />

            {/* Tela de Cadastro de Usuário - Requisito 3 */}
            <Route path="/cadastro" element={<Cadastro />} />
          </Routes>
        </div>
      </Router>
    </GoogleOAuthProvider>
  );
}

export default App;
